import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Feature Guide","description":"","frontmatter":{},"headers":[],"relativePath":"user/features.md","filePath":"user/features.md","lastUpdated":1775719799000}'),n={name:"user/features.md"};function r(s,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="feature-guide" tabindex="-1">Feature Guide <a class="header-anchor" href="#feature-guide" aria-label="Permalink to &quot;Feature Guide&quot;">​</a></h1><p>Complete guide to RustChat features.</p><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#messaging">Messaging</a></li><li><a href="#channels">Channels</a></li><li><a href="#search">Search</a></li><li><a href="#notifications">Notifications</a></li><li><a href="#settings">Settings</a></li></ul><hr><h2 id="messaging" tabindex="-1">Messaging <a class="header-anchor" href="#messaging" aria-label="Permalink to &quot;Messaging&quot;">​</a></h2><h3 id="sending-messages" tabindex="-1">Sending Messages <a class="header-anchor" href="#sending-messages" aria-label="Permalink to &quot;Sending Messages&quot;">​</a></h3><ul><li>Type in the composer at the bottom of a channel</li><li>Press <strong>Enter</strong> to send</li><li>Press <strong>Shift+Enter</strong> for a new line</li></ul><h3 id="editing-messages" tabindex="-1">Editing Messages <a class="header-anchor" href="#editing-messages" aria-label="Permalink to &quot;Editing Messages&quot;">​</a></h3><ol><li>Hover over your message</li><li>Click the <strong>...</strong> menu</li><li>Select <strong>Edit</strong></li></ol><h3 id="deleting-messages" tabindex="-1">Deleting Messages <a class="header-anchor" href="#deleting-messages" aria-label="Permalink to &quot;Deleting Messages&quot;">​</a></h3><ol><li>Hover over your message</li><li>Click the <strong>...</strong> menu</li><li>Select <strong>Delete</strong></li></ol><h3 id="markdown-formatting" tabindex="-1">Markdown Formatting <a class="header-anchor" href="#markdown-formatting" aria-label="Permalink to &quot;Markdown Formatting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Style</th><th>Syntax</th><th>Example</th></tr></thead><tbody><tr><td>Bold</td><td><code>**text**</code></td><td><strong>bold</strong></td></tr><tr><td>Italic</td><td><code>*text*</code></td><td><em>italic</em></td></tr><tr><td>Code</td><td><code>`code`</code></td><td><code>code</code></td></tr><tr><td>Code block</td><td><code>```</code></td><td>Multi-line code</td></tr><tr><td>Quote</td><td><code>&gt; text</code></td><td>Blockquote</td></tr><tr><td>Link</td><td><code>[text](url)</code></td><td><a href="https://example.com" target="_blank" rel="noreferrer">Link</a></td></tr></tbody></table><h3 id="mentions" tabindex="-1">Mentions <a class="header-anchor" href="#mentions" aria-label="Permalink to &quot;Mentions&quot;">​</a></h3><p>Use mentions to get someone&#39;s attention:</p><ul><li><code>@username</code> - Notify a specific user</li><li><code>@channel</code> - Notify everyone in the current channel</li><li><code>@all</code> - Notify everyone on the team (use sparingly)</li></ul><h3 id="threads" tabindex="-1">Threads <a class="header-anchor" href="#threads" aria-label="Permalink to &quot;Threads&quot;">​</a></h3><p>Keep conversations organized:</p><ol><li>Hover over a message</li><li>Click the <strong>Reply</strong> icon</li><li>Thread replies appear in the Right Sidebar</li></ol><h3 id="emoji-reactions" tabindex="-1">Emoji Reactions <a class="header-anchor" href="#emoji-reactions" aria-label="Permalink to &quot;Emoji Reactions&quot;">​</a></h3><p>React to messages quickly:</p><ol><li>Hover over a message</li><li>Click <strong>Add Reaction</strong></li><li>Select an emoji</li></ol><h3 id="file-uploads" tabindex="-1">File Uploads <a class="header-anchor" href="#file-uploads" aria-label="Permalink to &quot;File Uploads&quot;">​</a></h3><p>Share files:</p><ul><li><strong>Drag and drop</strong> files into the message pane</li><li>Click the <strong>+</strong> icon in the composer</li><li>Images and PDFs show previews</li></ul><hr><h2 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h2><h3 id="public-channels" tabindex="-1">Public Channels <a class="header-anchor" href="#public-channels" aria-label="Permalink to &quot;Public Channels&quot;">​</a></h3><ul><li>Open to anyone on the team</li><li>Marked with <strong>#</strong></li><li>Good for broad discussions</li></ul><h3 id="private-channels" tabindex="-1">Private Channels <a class="header-anchor" href="#private-channels" aria-label="Permalink to &quot;Private Channels&quot;">​</a></h3><ul><li>Invitation only</li><li>Marked with <strong>🔒</strong></li><li>For sensitive topics</li></ul><h3 id="creating-channels" tabindex="-1">Creating Channels <a class="header-anchor" href="#creating-channels" aria-label="Permalink to &quot;Creating Channels&quot;">​</a></h3><ol><li>Click <strong>+</strong> next to &quot;Channels&quot;</li><li>Choose <strong>Public</strong> or <strong>Private</strong></li><li>Enter a name</li><li>Add members (optional)</li></ol><h3 id="direct-messages-dms" tabindex="-1">Direct Messages (DMs) <a class="header-anchor" href="#direct-messages-dms" aria-label="Permalink to &quot;Direct Messages (DMs)&quot;">​</a></h3><p>1:1 conversations:</p><ol><li>Click <strong>+</strong> next to &quot;Direct Messages&quot;</li><li>Search for a teammate</li><li>Start chatting</li></ol><h3 id="group-messages" tabindex="-1">Group Messages <a class="header-anchor" href="#group-messages" aria-label="Permalink to &quot;Group Messages&quot;">​</a></h3><p>Group DMs with multiple people:</p><ol><li>Click <strong>+</strong> next to &quot;Direct Messages&quot;</li><li>Select multiple people</li><li>Start the conversation</li></ol><hr><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><h3 id="basic-search" tabindex="-1">Basic Search <a class="header-anchor" href="#basic-search" aria-label="Permalink to &quot;Basic Search&quot;">​</a></h3><p>Type keywords in the search bar at the top.</p><h3 id="search-filters" tabindex="-1">Search Filters <a class="header-anchor" href="#search-filters" aria-label="Permalink to &quot;Search Filters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Filter</th><th>Syntax</th><th>Description</th></tr></thead><tbody><tr><td>From user</td><td><code>from:@username</code></td><td>Messages from specific person</td></tr><tr><td>In channel</td><td><code>in:#channel</code></td><td>Messages in specific channel</td></tr><tr><td>With file</td><td><code>has:file</code></td><td>Messages with attachments</td></tr><tr><td>Before date</td><td><code>before:2024-01-01</code></td><td>Messages before date</td></tr><tr><td>After date</td><td><code>after:2024-01-01</code></td><td>Messages after date</td></tr></tbody></table><h3 id="jump-to-results" tabindex="-1">Jump to Results <a class="header-anchor" href="#jump-to-results" aria-label="Permalink to &quot;Jump to Results&quot;">​</a></h3><p>Click any search result to jump to that point in history.</p><h3 id="pinned-messages" tabindex="-1">Pinned Messages <a class="header-anchor" href="#pinned-messages" aria-label="Permalink to &quot;Pinned Messages&quot;">​</a></h3><p>Important messages can be pinned:</p><ul><li>Click the <strong>Pin</strong> icon in the channel header to view pinned messages</li></ul><hr><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><h3 id="desktop-notifications" tabindex="-1">Desktop Notifications <a class="header-anchor" href="#desktop-notifications" aria-label="Permalink to &quot;Desktop Notifications&quot;">​</a></h3><p>Enable in <strong>Settings &gt; Notifications</strong>:</p><ul><li>Browser notifications</li><li>Desktop app notifications</li></ul><h3 id="email-notifications" tabindex="-1">Email Notifications <a class="header-anchor" href="#email-notifications" aria-label="Permalink to &quot;Email Notifications&quot;">​</a></h3><p>Configure when to receive emails:</p><ul><li>Mentions and DMs</li><li>Daily/weekly digests</li></ul><h3 id="channel-muting" tabindex="-1">Channel Muting <a class="header-anchor" href="#channel-muting" aria-label="Permalink to &quot;Channel Muting&quot;">​</a></h3><p>Mute noisy channels:</p><ol><li>Click the channel header</li><li>Select <strong>Mute Channel</strong></li></ol><h3 id="notification-preferences" tabindex="-1">Notification Preferences <a class="header-anchor" href="#notification-preferences" aria-label="Permalink to &quot;Notification Preferences&quot;">​</a></h3><p>Customize in <strong>Settings &gt; Notifications</strong>:</p><ul><li>What triggers notifications</li><li>Sound settings</li><li>Email frequency</li></ul><hr><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="profile-settings" tabindex="-1">Profile Settings <a class="header-anchor" href="#profile-settings" aria-label="Permalink to &quot;Profile Settings&quot;">​</a></h3><p>Update in <strong>Settings &gt; Profile</strong>:</p><ul><li>Display name</li><li>Avatar</li><li>Bio</li></ul><h3 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h3><p>Customize in <strong>Settings &gt; Display</strong>:</p><ul><li>Light/Dark theme</li><li>Font size</li><li>Message density</li></ul><h3 id="language-timezone" tabindex="-1">Language &amp; Timezone <a class="header-anchor" href="#language-timezone" aria-label="Permalink to &quot;Language &amp; Timezone&quot;">​</a></h3><p>Set in <strong>Settings &gt; Display</strong>:</p><ul><li>Language preference</li><li>Local timezone</li></ul><h3 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h3><p>View all shortcuts with <strong>Ctrl+/</strong> (or <strong>Cmd+/</strong> on Mac)</p><p>Common shortcuts:</p><table tabindex="0"><thead><tr><th>Action</th><th>Shortcut</th></tr></thead><tbody><tr><td>New message</td><td><code>Ctrl+N</code></td></tr><tr><td>Search</td><td><code>Ctrl+K</code></td></tr><tr><td>Previous channel</td><td><code>Alt+Up</code></td></tr><tr><td>Next channel</td><td><code>Alt+Down</code></td></tr><tr><td>Settings</td><td><code>Ctrl+,</code></td></tr></tbody></table><hr><p><em>For troubleshooting: See <a href="./troubleshooting">Troubleshooting</a></em></p>',82)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
